"""data_pull.pyPulls historical financial statement data for a company from the SEC EDGAR API.Handles inconsistent XBRL tagging by trying multiple tag names per line item."""import requestsimport pandas as pdimport jsonimport os# ---- CONFIG ----CIK = "0000077476"  # PepsiCo. Find others at https://www.sec.gov/cgi-bin/browse-edgarHEADERS = {"User-Agent": "Roland Lapa laparoland@gmail.com"}# Priority-ordered XBRL tags for each line item.# The script tries the first tag; if not found, falls back to the next.TAG_MAP = {    "revenue": ["RevenueFromContractWithCustomerExcludingAssessedTax", "Revenues", "SalesRevenueNet"],    "cogs": ["CostOfGoodsAndServicesSold", "CostOfRevenue"],    "sga": ["SellingGeneralAndAdministrativeExpense"],    "operating_income": ["OperatingIncomeLoss"],    "interest_expense": ["InterestExpense", "InterestExpenseDebt"],    "pretax_income": ["IncomeLossFromContinuingOperationsBeforeIncomeTaxesExtraordinaryItemsNoncontrollingInterest",                       "IncomeLossFromContinuingOperationsBeforeIncomeTaxesMinorityInterestAndIncomeLossFromEquityMethodInvestments"],    "tax_expense": ["IncomeTaxExpenseBenefit"],    "net_income": ["NetIncomeLoss"],    "total_assets": ["Assets"],    "total_liabilities": ["Liabilities"],    "total_equity": ["StockholdersEquity", "StockholdersEquityIncludingPortionAttributableToNoncontrollingInterest"],    "cash": ["CashAndCashEquivalentsAtCarryingValue"],    "receivables": ["AccountsReceivableNetCurrent", "ReceivablesNetCurrent"],    "inventory": ["InventoryNet"],    "payables": ["AccountsPayableCurrent"],    "ppe_net": ["PropertyPlantAndEquipmentNet"],    "capex": ["PaymentsToAcquirePropertyPlantAndEquipment"],    "da": ["DepreciationDepletionAndAmortization", "DepreciationAmortizationAndAccretionNet"],    "current_assets": ["AssetsCurrent"],    "current_liabilities": ["LiabilitiesCurrent"],}def fetch_company_facts(cik: str) -> dict:    """Pull the full XBRL companyfacts JSON for a given CIK."""    url = f"https://data.sec.gov/api/xbrl/companyfacts/CIK{cik}.json"    r = requests.get(url, headers=HEADERS)    r.raise_for_status()    return r.json()def extract_annual_values(facts: dict, tags: list) -> pd.DataFrame:    """    Given a list of candidate XBRL tags, return annual values as a    DataFrame indexed by fiscal year.    Handles two types of XBRL facts differently:    - Duration facts (income statement items like revenue): have a      start and end date. We derive fiscal year from 'end' and keep      only entries covering roughly a full year (350-380 days) to      exclude quarterly figures.    - Instant facts (balance sheet items like total assets): only      have an 'end' (snapshot) date, no duration to check.    Note: EDGAR's 'fy' field marks which 10-K filing a data point came    from, not necessarily which year it covers - each 10-K reports the    current year plus prior years as comparatives, which can share the    same 'fy' label. We derive the true fiscal year from 'end' instead.    """    frames = []    for tag in tags:        try:            entries = facts["facts"]["us-gaap"][tag]["units"]["USD"]        except KeyError:            continue        df = pd.DataFrame(entries)        df = df[(df["form"] == "10-K") & (df["fp"] == "FY")]        if df.empty:            continue        df["end"] = pd.to_datetime(df["end"])        if "start" in df.columns:            # Duration fact (income statement item) - filter to full-year periods            df["start"] = pd.to_datetime(df["start"])            duration_days = (df["end"] - df["start"]).dt.days            df = df[(duration_days >= 350) & (duration_days <= 380)]        # else: instant fact (balance sheet item) - no duration to check        if df.empty:            continue        df["fiscal_year"] = df["end"].dt.year        df = df.sort_values("filed").drop_duplicates(subset="fiscal_year", keep="last")        df = df[["fiscal_year", "val"]].set_index("fiscal_year")        frames.append(df)    if not frames:        return pd.DataFrame(columns=["value"]).rename_axis("fy")    result = frames[0]    for f in frames[1:]:        result = result.combine_first(f)    return result.rename(columns={"val": tags[0]}).rename_axis("fy")def build_financials_table(facts: dict) -> pd.DataFrame:    """Combine all line items into one DataFrame, one row per fiscal year."""    all_series = []    for line_item, tags in TAG_MAP.items():        series = extract_annual_values(facts, tags)        series.columns = [line_item]        all_series.append(series)    combined = pd.concat(all_series, axis=1)    combined = combined.sort_index()    return combinedif __name__ == "__main__":    print("Fetching data from SEC EDGAR...")    facts = fetch_company_facts(CIK)    company_name = facts["entityName"]    print(f"Pulled data for: {company_name}")    financials = build_financials_table(facts)    print("\nFinancials table (in USD):")    print(financials)    # Save both a raw JSON backup and the clean CSV    os.makedirs("../data", exist_ok=True)    with open("../data/raw_companyfacts.json", "w") as f:        json.dump(facts, f)    financials.to_csv("../data/financials_annual.csv")    print("\nSaved to data/financials_annual.csv and data/raw_companyfacts.json")    